<template>
  <div class="min-h-screen bg-gradient-to-br from-slate-900 via-slate-800 to-slate-900 flex items-center justify-center p-4">
    <div class="w-full max-w-md">
      <div class="bg-white rounded-xl shadow-sm border border-slate-200 transition-all duration-200 p-8 backdrop-blur-lg bg-white/95 border border-white/20">
        <div class="mb-8">
          <h1 class="text-3xl font-bold text-slate-900 mb-2">Create account</h1>
          <p class="text-slate-600">Register as a customer to request refunds and manage your payments</p>
        </div>

        <form @submit.prevent="handleRegister" class="space-y-5">
          <div>
            <label for="email" class="block text-sm font-medium text-slate-700 mb-1.5">Email Address</label>
            <input id="email" v-model="form.email" type="email" required placeholder="you@example.com" class="w-full px-3 py-2 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder-slate-400" />
            <p v-if="errors.email" class="mt-2 text-sm text-red-600">{{ errors.email }}</p>
          </div>

          <div>
            <label for="password" class="block text-sm font-medium text-slate-700 mb-1.5">Password</label>
            <input id="password" v-model="form.password" type="password" required placeholder="••••••••" class="w-full px-3 py-2 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder-slate-400" />
          </div>

          <div>
            <label for="confirm" class="block text-sm font-medium text-slate-700 mb-1.5">Confirm password</label>
            <input id="confirm" v-model="form.confirmPassword" type="password" required placeholder="••••••••" class="w-full px-3 py-2 rounded-lg border border-slate-300 bg-white text-slate-900 placeholder-slate-400" />
            <p v-if="errors.password" class="mt-2 text-sm text-red-600">{{ errors.password }}</p>
          </div>

          <button type="submit" :disabled="isLoading" class="w-full px-4 py-2.5 rounded-lg font-semibold bg-slate-900 text-white">
            <span v-if="isLoading">Creating account...</span>
            <span v-else>Create account</span>
          </button>
        </form>

        <div class="mt-4 text-center">
          <p class="text-sm text-slate-600">Already have an account? <router-link to="/login" class="text-slate-900 font-medium">Sign in</router-link></p>
        </div>
      </div>

      <p class="text-center text-sm text-slate-400 mt-6">
        Payment Gateway Platform
        <br />
        <span class="text-xs">Secure customer payment management</span>
      </p>
    </div>
  </div>
</template>

<script setup lang="ts">
import { reactive, ref } from 'vue'
import { useRouter, useRoute } from 'vue-router'
import { authService } from '@/services/auth'
import { useAuthStore } from '@/stores/auth'
import { useNotificationStore } from '@/stores/notifications'

const router = useRouter()
const route = useRoute()
const authStore = useAuthStore()
const notificationStore = useNotificationStore()

const form = reactive({
  email: '',
  password: '',
  confirmPassword: '',
})

const errors = ref({ email: '', password: '' })
const isLoading = ref(false)

async function handleRegister() {
  errors.value = { email: '', password: '' }

  if (!form.email) {
    errors.value.email = 'Email is required'
    return
  }
  if (!form.password) {
    errors.value.password = 'Password is required'
    return
  }
  if (form.password !== form.confirmPassword) {
    errors.value.password = 'Passwords do not match'
    return
  }

  isLoading.value = true
  try {
    // Create account
    await authService.register(form.email, form.password)

    // Login to initialize session
    await authStore.login(form.email, form.password)
    notificationStore.success('Account created and signed in')

    const returnTo = route.query.returnTo as string | undefined
    router.push(returnTo || '/dashboard')
  } catch (err) {
    notificationStore.error('Registration failed. Please check your information.')
  } finally {
    isLoading.value = false
  }
}
</script>

